module RefModule (
    input wire clk,
    input wire rst,
    input wire signal_in,
    output reg edge_out
);
    reg signal_in_d;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) begin
            edge_out <= 0;
            signal_in_d <= 0;
        end else begin
            edge_out <= (signal_in && !signal_in_d);
            signal_in_d <= signal_in;
        end
    end
endmodule
